def configure_kong(client: KongAdminClient):
    services = [
        {
            "name": "users-service",
            "url": "http://users-upstream:80",
            "routes": [
                {
                    "name": "users-route",
                    "paths": ["/users"],
                    "methods": ["GET", "POST", "PUT", "DELETE"],
                    "strip_path": True,
                    "preserve_host": False,
                }
            ],
        },
        {
            "name": "orders-service",
            "url": "http://orders-upstream:80",
            "routes": [
                {
                    "name": "orders-route",
                    "paths": ["/orders"],
                    "methods": ["GET", "POST", "PUT", "DELETE"],
                    "strip_path": True,
                    "preserve_host": False,
                }
            ],
        },
    ]

    upstreams = [
        {
            "name": "users-upstream",
            "algorithm": "round-robin",
            "targets": [
                {"target": "users-1:8080", "weight": 100},
                {"target": "users-2:8080", "weight": 100},
            ],
        },
        {
            "name": "orders-upstream",
            "algorithm": "round-robin",
            "targets": [
                {"target": "orders-1:8080", "weight": 100},
                {"target": "orders-2:8080", "weight": 100},
            ],
        },
    ]

    results = {"services": [], "routes": [], "upstreams": [], "targets": []}

    for upstream in upstreams:
        try:
            results["upstreams"].append(client.create_upstream(
                name=upstream["name"],
                algorithm=upstream.get("algorithm"),
            ))
        except Exception as e:
            results["upstreams"].append({"name": upstream["name"], "error": str(e)})
        for target in upstream.get("targets", []):
            try:
                results["targets"].append(client.create_target(
                    upstream_name=upstream["name"],
                    target=target["target"],
                    weight=target.get("weight", 100),
                ))
            except Exception as e:
                results["targets"].append({"upstream": upstream["name"], "target": target["target"], "error": str(e)})

    for service in services:
        try:
            results["services"].append(client.create_service(
                name=service["name"],
                url=service.get("url"),
            ))
        except Exception as e:
            results["services"].append({"name": service["name"], "error": str(e)})

        for route in service.get("routes", []):
            try:
                results["routes"].append(client.create_route(
                    service_name=service["name"],
                    route_name=route["name"],
                    paths=route.get("paths"),
                    hosts=route.get("hosts"),
                    methods=route.get("methods"),
                    strip_path=route.get("strip_path"),
                    preserve_host=route.get("preserve_host"),
                    protocols=route.get("protocols"),
                ))
            except Exception as e:
                results["routes"].append({"service": service["name"], "route": route["name"], "error": str(e)})

    return results


def main():
    client = KongAdminClient(KONG_ADMIN_URL, timeout=REQUEST_TIMEOUT)

    if not client.wait_until_ready():
        print(f"ERROR: Kong Admin API not reachable at {KONG_ADMIN_URL}", file=sys.stderr)
        sys.exit(1)

